1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies (underpopulation, 0 neighbors) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it.todo("two adjacent cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []");
12	  it("live cell with 2 neighbors survives (rule 2 - survival)", () => {
13	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
14	    expect(result).toContainEqual([1, 0]);
15	  });
16	  it.todo("live cell with 3 neighbors survives (rule 2 - survival)");
17	  it.todo("live cell with 4 neighbors dies (rule 3 - overpopulation)");
18	  it.todo("dead cell with exactly 3 neighbors becomes alive (rule 4 - reproduction) — [(0,0),(1,0),(0,1)] produces (1,1)");
19	  it.todo("block still life stays unchanged — [(0,0),(1,0),(0,1),(1,1)] → same");
20	  it.todo("blinker vertical → horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]");
21	  it.todo("handles negative coordinates correctly");
22	});
